INSERT INTO `problem_types` (`id`, `subtopic_id`, `order`, `title`, `slug`, `description`, `created_at`) VALUES (1,1,1,'Расчет скорости и пути','speed-distance','Прямая задача: по известным скорости и времени найти путь','2026-06-19 14:15:42'),(2,1,2,'Графики равномерного движения','uniform-graphs','Задачи на чтение и построение графиков v(t) и s(t)','2026-06-19 14:15:42'),(3,2,3,'Уравнения кинематики','kinematic-equations','Применение основных уравнений равноускоренного движения','2026-06-19 14:15:42'),(4,2,4,'Свободное падение тел','free-fall','Движение тела с ускорением свободного падения g','2026-06-19 14:15:42'),(5,3,5,'Период и частота вращения','period-frequency','Расчет периода, частоты и линейной скорости','2026-06-19 14:15:42'),(6,3,6,'Угловая и линейная скорость','angular-linear','Связь между угловой и линейной скоростью при движении по окружности','2026-06-19 14:15:42'),(7,4,7,'Относительность движения','relative-motion','Сложение скоростей, переход между системами отсчета','2026-06-19 14:15:42'),(8,4,8,'Задачи на встречное и попутное движение','meeting-chasing','Задачи на встречу и догоняние','2026-06-19 14:15:42');
